  layout: SlideLayout;

  // Visibility Overrides (True = Keep Visible / Disable Fix)
  skipTextEnterVisibility?: boolean;
  skipTextExitVisibility?: boolean;
  skipImageEnterVisibility?: boolean;
  skipImageExitVisibility?: boolean;
}

