import { useState, useEffect, useRef } from 'react';
import { SlideData, INITIAL_SLIDE, createNewSlide, SlideLayout, ThemeId, TypographyId, THEMES, TYPOGRAPHY_STYLES, ProjectMetadata } from '../types';
import { supabase } from '../services/supabaseClient';

export const usePresentation = () => {
    // Current Project State
    const [currentProjectId, setCurrentProjectId] = useState<string | number | null>(null);
    const [currentProjectName, setCurrentProjectName] = useState<string>("Untitled Project");
    const [slides, setSlides] = useState<SlideData[]>([INITIAL_SLIDE]);
    const [currentSlideIndex, setCurrentSlideIndex] = useState(0);

    // App State
    const [saveStatus, setSaveStatus] = useState<'idle' | 'saving' | 'saved' | 'error'>('idle');
    const [isLoaded, setIsLoaded] = useState(false);
    const isFirstLoad = useRef(true);

    // Project List State
    const [savedProjects, setSavedProjects] = useState<ProjectMetadata[]>([]);
    const [isLoadingProjects, setIsLoadingProjects] = useState(false);

    const currentSlide = slides[currentSlideIndex] || slides[0];

    // --- Persistence Logic ---

    // Fetch Project List
    const fetchProjects = async () => {
        setIsLoadingProjects(true);
        try {
            // Select relevant fields. Order by updated_at descending
            const { data, error } = await supabase
                .from('presentations')
                .select('id, name, updated_at')
                .order('updated_at', { ascending: false });

            if (error) throw error;
            if (data) {
                setSavedProjects(data as ProjectMetadata[]);
            }
        } catch (e) {
            console.error("Failed to fetch projects list:", e);
        } finally {
            setIsLoadingProjects(false);
        }
    };

    // Initial Load of Project List
    useEffect(() => {
        fetchProjects();
        setIsLoaded(true);
        setTimeout(() => { isFirstLoad.current = false; }, 500);
    }, []);

    // Load Specific Project
    const loadRemoteProject = async (id: string | number) => {
        setIsLoaded(false);
        try {
            const { data, error } = await supabase
                .from('presentations')
                .select('*')
                .eq('id', id)
                .single();

            if (error) throw error;
            if (data) {
                // If opening an archived project, visually strip the tag for the editor title
                const cleanName = data.name.replace('[ARCHIVED] ', '');

                setSlides(data.slides || [INITIAL_SLIDE]);
                setCurrentProjectId(data.id);
                setCurrentProjectName(cleanName);
                setCurrentSlideIndex(0);
            }
        } catch (e) {
            console.error("Failed to load project:", e);
            alert("Could not load project.");
            fetchProjects(); // Refresh list to verify
        } finally {
            setIsLoaded(true);
        }
    };

    // Create New Remote Project
    const createNewRemoteProject = async (name: string, initialSlides: SlideData[]) => {
        setIsLoaded(false);
        try {
            const { data, error } = await supabase
                .from('presentations')
                .insert([{
                    name: name,
                    slides: initialSlides,
                    updated_at: new Date().toISOString()
                }])
                .select()
                .single();

            if (error) throw error;
            if (data) {
                setCurrentProjectId(data.id);
                setCurrentProjectName(data.name);
                setSlides(initialSlides);
                setCurrentSlideIndex(0);
                fetchProjects(); // Refresh list
            }
        } catch (e) {
            console.error("Failed to create project:", e);
            // Fallback for offline or error: just set state
            setSlides(initialSlides);
            setCurrentProjectName(name);
            setCurrentProjectId(Date.now()); // Temp ID
            setCurrentSlideIndex(0);
        } finally {
            setIsLoaded(true);
        }
    };

    // Duplicate Project
    const duplicateProject = async (id: string | number) => {
        try {
            const { data: original, error: fetchError } = await supabase
                .from('presentations')
                .select('*')
                .eq('id', id)
                .single();

            if (fetchError) throw fetchError;
            if (!original) return;

            // Ensure we don't duplicate the archived tag if it exists
            const rawName = original.name.replace('[ARCHIVED] ', '');
            const newName = `Copy of ${rawName}`;

            const { error: insertError } = await supabase
                .from('presentations')
                .insert([{
                    name: newName,
                    slides: original.slides,
                    updated_at: new Date().toISOString()
                }]);

            if (insertError) throw insertError;
            fetchProjects();
        } catch (e) {
            console.error("Failed to duplicate:", e);
        }
    };

    // Save Helper
    const saveToCloud = async (slidesToSave: SlideData[]) => {
        if (!currentProjectId) return; 

        setSaveStatus('saving');
        try {
            const { error } = await supabase
                .from('presentations')
                .upsert({ 
                    id: currentProjectId, 
                    name: currentProjectName,
                    slides: slidesToSave,
                    updated_at: new Date().toISOString()
                });

            if (error) throw error;
            setSaveStatus('saved');
            setTimeout(() => setSaveStatus('idle'), 2000);
            fetchProjects(); 
        } catch (error: any) {
            console.error("Failed to save to Supabase:", error);
            setSaveStatus('error');
        }
    };

    // Rename Project
    const renameProject = async (id: string | number, newName: string) => {
        try {
            const { error } = await supabase
                .from('presentations')
                .update({ name: newName })
                .eq('id', id);

            if (error) throw error;

            if (id === currentProjectId) {
                setCurrentProjectName(newName);
            }
            fetchProjects();
        } catch (e) {
            console.error("Failed to rename:", e);
        }
    };

    // Toggle Archive Status (Replaces Delete)
    const toggleArchiveStatus = async (id: string | number) => {
        const project = savedProjects.find(p => p.id === id);
        if (!project) return;

        const isArchived = project.name.startsWith('[ARCHIVED] ');
        const newName = isArchived 
            ? project.name.replace('[ARCHIVED] ', '') 
            : `[ARCHIVED] ${project.name}`;

        // Optimistic Update
        const previousProjects = [...savedProjects];
        setSavedProjects(prev => prev.map(p => 
            p.id === id ? { ...p, name: newName } : p
        ));

        try {
            const { error } = await supabase
                .from('presentations')
                .update({ name: newName })
                .eq('id', id);

            if (error) throw error;
        } catch (e: any) {
            console.error("Failed to toggle archive:", e);
            alert("Failed to update project status.");
            setSavedProjects(previousProjects);
        }
    };

    // Auto-Save
    useEffect(() => {
        if (!isLoaded || isFirstLoad.current || !currentProjectId) return;
        const timeoutId = setTimeout(() => {
            saveToCloud(slides);
        }, 2000);
        return () => clearTimeout(timeoutId);
    }, [slides, isLoaded, currentProjectId, currentProjectName]);


    // --- Slide Operations ---

    const handleUpdateSlide = (updatedSlide: SlideData) => {
        const oldSlide = slides[currentSlideIndex];
        let newSlides = slides.map((s, index) => index === currentSlideIndex ? updatedSlide : s);

        // Apply Global changes logic (Keep Theme and Typography global)
        if (oldSlide.theme !== updatedSlide.theme) {
            newSlides = newSlides.map(s => ({ ...s, theme: updatedSlide.theme }));
        }
        if (oldSlide.typography !== updatedSlide.typography) {
            newSlides = newSlides.map(s => ({ ...s, typography: updatedSlide.typography }));
        }

        setSlides(newSlides);
    };

    const handleAddSlide = (layout: SlideLayout = 'text-image') => {
        const newSlide = createNewSlide(layout);
        const refSlide = slides[currentSlideIndex] || slides[0];
        // Inherit styles
        newSlide.theme = refSlide.theme || 'cyber-future';
        newSlide.typography = refSlide.typography || 'modern-sans';
        newSlide.textTransition = refSlide.textTransition || 'slide-up';
        newSlide.imageTransition = refSlide.imageTransition || 'zoom-in';
        newSlide.textOutroTransition = refSlide.textOutroTransition || 'none';
        newSlide.imageOutroTransition = refSlide.imageOutroTransition || 'none';

        // Inherit Global Font Sizes
        newSlide.badgeFontSize = refSlide.badgeFontSize;
        newSlide.titleFontSize = refSlide.titleFontSize;
        newSlide.descriptionFontSize = refSlide.descriptionFontSize;

        const lastSlide = slides[slides.length - 1];
        if (lastSlide && lastSlide.badge.startsWith('Step ')) {
            const num = parseInt(lastSlide.badge.split(' ')[1]);
            if (!isNaN(num)) newSlide.badge = `Step ${num + 1}`;
        }

        setSlides([...slides, newSlide]);
        setCurrentSlideIndex(slides.length);
    };

    const handleDuplicateSlide = (index: number) => {
        const slide = slides[index];
        if (!slide) return;
        const newSlide = { ...slide, id: Date.now().toString() };
        const newSlides = [...slides];
        newSlides.splice(index + 1, 0, newSlide);
        setSlides(newSlides);
        setCurrentSlideIndex(index + 1);
    };

    const handleDeleteSlide = (index: number) => {
        if (slides.length <= 1) return;
        const newSlides = slides.filter((_, i) => i !== index);
        setSlides(newSlides);
        if (currentSlideIndex >= index && currentSlideIndex > 0) {
            setCurrentSlideIndex(currentSlideIndex - 1);
        } else if (currentSlideIndex >= newSlides.length) {
            setCurrentSlideIndex(newSlides.length - 1);
        }
    };

    const handleReorderSlides = (from: number, to: number) => {
        if (from === to) return;
        const newSlides = [...slides];
        const [moved] = newSlides.splice(from, 1);
        newSlides.splice(to, 0, moved);
        setSlides(newSlides);

        if (currentSlideIndex === from) setCurrentSlideIndex(to);
        else if (from < currentSlideIndex && to >= currentSlideIndex) setCurrentSlideIndex(currentSlideIndex - 1);
        else if (from > currentSlideIndex && to <= currentSlideIndex) setCurrentSlideIndex(currentSlideIndex + 1);
    };

    const applyTheme = (id: ThemeId) => setSlides(slides.map(s => ({ ...s, theme: id })));
    const applyTypography = (id: TypographyId) => setSlides(slides.map(s => ({ ...s, typography: id })));

    // NEW: Update Global Font Size
    const updateGlobalFontSize = (field: 'badgeFontSize' | 'titleFontSize' | 'descriptionFontSize', value: number) => {
        setSlides(slides.map(s => ({ ...s, [field]: value })));
    };

    const randomizeLook = () => {
        const t = THEMES[Math.floor(Math.random() * THEMES.length)];
        const f = TYPOGRAPHY_STYLES[Math.floor(Math.random() * TYPOGRAPHY_STYLES.length)];
        setSlides(slides.map(s => ({ ...s, theme: t.id, typography: f.id })));
    };

    // --- New Project Management ---

    const startNewProject = () => {
        const dateStr = new Date().toLocaleString();
        const name = `Project - ${dateStr}`;
        const freshSlide = createNewSlide('text-image');

        createNewRemoteProject(name, [freshSlide]);
    };

    const importProjectFile = (file: File) => {
        const reader = new FileReader();
        reader.onload = (e) => {
            try {
                const json = JSON.parse(e.target?.result as string);
                if (Array.isArray(json) && json.length > 0 && json[0].id) {
                    const dateStr = new Date().toLocaleString();
                    const name = `Imported - ${dateStr}`;
                    createNewRemoteProject(name, json as SlideData[]);
                } else {
                    alert("Invalid project file.");
                }
            } catch (err) {
                console.error(err);
                alert("Failed to parse project file.");
            }
        };
        reader.readAsText(file);
    };

    const downloadProjectFile = () => {
        try {
            const blob = new Blob([JSON.stringify(slides, null, 2)], { type: "application/json" });
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = `${currentProjectName.replace(/[^a-z0-9]/gi, '_').toLowerCase()}.json`;
            document.body.appendChild(a);
            a.click();
            document.body.removeChild(a);
            URL.revokeObjectURL(url);
        } catch(e) { console.error(e); }
    };

    return {
        // State
        slides,
        currentSlideIndex,
        currentSlide,
        saveStatus,
        isLoaded,
        currentProjectId,
        currentProjectName,
        savedProjects,
        isLoadingProjects,

        // Setters
        setSlides,
        setCurrentSlideIndex,

        // Actions
        updateSlide: handleUpdateSlide,
        addSlide: handleAddSlide,
        duplicateSlide: handleDuplicateSlide,
        deleteSlide: handleDeleteSlide,
        reorderSlide: handleReorderSlides,
        manualSave: () => saveToCloud(slides),

        // Styles
        applyTheme,
        applyTypography,
        updateGlobalFontSize, // Exposed
        randomizeLook,

        // Project Management
        startNewProject,
        loadRemoteProject,
        importProjectFile,
        downloadProjectFile,
        renameProject,
        toggleArchiveStatus,
        duplicateProject,
        fetchProjects
    };
};

import React from 'react';
import { SlideData } from '../types';

interface SlideRendererProps {
  data: SlideData;
  scale?: number;
  animate?: boolean;
  progress?: number; // 0 to 100
}

const SlideRenderer: React.FC<SlideRendererProps> = ({ 
    data, 
    scale = 1, 
    animate = true, 
    progress = 0 
}) => {
  const { 
    theme, 
    typography = 'modern-sans', // Default fallback
    badge, 
    title, 
    description, 
    imageUrl, 
    textTransition = 'slide-up', 
    imageTransition = 'zoom-in',
    textOutroTransition = 'none',
    imageOutroTransition = 'none',

    // Default to 1s if undefined for backward compatibility
    textTransitionDuration = 1,
    imageTransitionDuration = 1,
    textOutroDuration = 1,
    imageOutroDuration = 1,

    layout = 'text-image', // Default fallback

    // Visibility Overrides
    skipTextEnterVisibility = false,
    skipTextExitVisibility = false,
    skipImageEnterVisibility = false,
    skipImageExitVisibility = false,

    // Font Overrides
    badgeFontSize,
    titleFontSize,
    descriptionFontSize,
  } = data;

  // Base Slide Dimensions (16:9 Aspect Ratio based on 1920x1080)
  const width = 1920;
  const height = 1080;

  // Common wrapper style
  const wrapperStyle: React.CSSProperties = {
    width: `${width}px`,
    height: `${height}px`,
    transform: `scale(${scale})`,
    transformOrigin: 'center center',
    overflow: 'hidden',
    position: 'relative',
    display: 'flex',
    boxShadow: '0 0 50px rgba(0,0,0,0.5)',
  };

  // --- Animation Logic ---
  const durationSeconds = data.duration || 5;
  const currentSeconds = durationSeconds * (progress / 100);

  const getControlledAnimationStyle = (baseDelayMs: number, type: 'intro' | 'outro' = 'intro', durationVal: number = 1): React.CSSProperties => {
    if (!animate) return {};

    const elapsedSeconds = currentSeconds;

    let calculatedDelayStr = '';

    if (type === 'intro') {
        calculatedDelayStr = `calc(${baseDelayMs}ms - ${elapsedSeconds}s)`;
    } else {
        const outroStartMs = (durationSeconds * 1000) - (durationVal * 1000);
        calculatedDelayStr = `calc(${outroStartMs}ms - ${elapsedSeconds}s)`;
    }

    return {
      animationPlayState: 'paused',
      animationDelay: calculatedDelayStr,
      animationFillMode: 'both',
      animationIterationCount: 1,
      animationDuration: `${durationVal}s` // Override CSS default
    };
  };

  const getAnimationClass = (transition: string, type: 'intro' | 'outro') => {
    if (!animate || transition === 'none') return '';
    return `anim-${transition}${type === 'outro' ? '-out' : ''}`;
  };

  const textIntroClass = getAnimationClass(textTransition, 'intro');
  const textOutroClass = getAnimationClass(textOutroTransition, 'outro');
  const imgIntroClass = getAnimationClass(imageTransition, 'intro');
  const imgOutroClass = getAnimationClass(imageOutroTransition, 'outro');

  // FOUC Prevention & Clean Cut Logic
  const isFirstFrame = animate && progress <= 0.0001;
  const isLastFrame = animate && progress >= 99.9999;

  // Helper to determine style overrides for start/end frames
  // If "Keep Visible" is checked, we MUST force visibility properties to override
  // any potential animation states (like opacity: 0 from a fade-in) that might be applied.
  const getVisibilityStyle = (isFrame: boolean, skipVisibility: boolean | undefined) => {
      if (!isFrame) return {};
      if (skipVisibility) {
          return {
              visibility: 'visible' as const,
              opacity: 1,
              transform: 'none',
              filter: 'none',
              animationName: 'none' // Disable animation to prevent it from hiding content
          };
      }
      return { visibility: 'hidden' as const };
  };

  const textIntroStyle: React.CSSProperties = {
      ...getControlledAnimationStyle(0, 'intro', textTransitionDuration),
      ...getVisibilityStyle(isFirstFrame, skipTextEnterVisibility)
  };
  const textOutroStyle: React.CSSProperties = {
      ...getControlledAnimationStyle(0, 'outro', textOutroDuration),
      ...getVisibilityStyle(isLastFrame, skipTextExitVisibility)
  };

  const imgIntroStyle: React.CSSProperties = {
      ...getControlledAnimationStyle(0, 'intro', imageTransitionDuration),
      ...getVisibilityStyle(isFirstFrame, skipImageEnterVisibility)
  };
  const imgOutroStyle: React.CSSProperties = {
      ...getControlledAnimationStyle(0, 'outro', imageOutroDuration),
      ...getVisibilityStyle(isLastFrame, skipImageExitVisibility)
  };

  // --- Title Pulse Logic (Global Continuous) ---
  // If not animating (thumbnail), force scale to 1. 
  // If animating, leave transform empty so CSS variable takes over.
  const pulseWrapperStyle: React.CSSProperties = !animate ? { transform: 'scale(1)' } : {};

  // --- Ripple Effect Logic ---
  const getRippleStyle = (offsetSeconds: number): React.CSSProperties => {
      if (!animate) return {}; 

      return {
          animationPlayState: 'paused',
          animationDelay: `calc(${offsetSeconds}s - ${currentSeconds}s)`,
      };
  };

  const titleStyle: React.CSSProperties = {
    fontSize: titleFontSize ? `${titleFontSize}px` : 'var(--slide-title-size)',
  };

  // Layout Logic
  const isTextOnly = layout === 'text-only';

  // Wrapper classes for layout
  const containerClasses = isTextOnly 
    ? `theme-${theme} typography-${typography} flex-col items-center justify-center p-[100px] text-center`
    : `theme-${theme} typography-${typography} flex-row items-center p-[70px] gap-20`;

  // Text container classes
  const textContainerClasses = isTextOnly
    ? `w-full z-10 flex flex-col justify-center items-center text-center anim-outro-wrapper ${textOutroClass}`
    : `flex-1 z-10 flex flex-col justify-center items-start text-left anim-outro-wrapper ${textOutroClass}`;

  // Badge alignment for text-only
  const badgeClasses = isTextOnly 
    ? "badge inline-block px-10 py-4 rounded-full font-bold uppercase mb-10 tracking-wider w-fit mx-auto whitespace-nowrap"
    : "badge inline-block px-10 py-4 rounded-full font-bold uppercase mb-10 tracking-wider w-fit whitespace-nowrap";

  const descClasses = isTextOnly
    ? "slide-description leading-relaxed opacity-85 max-w-[80%] mx-auto whitespace-pre-wrap"
    : "slide-description leading-relaxed opacity-85 max-w-[90%] whitespace-pre-wrap";

  return (
    <div 
        style={wrapperStyle} 
        className={containerClasses}
    >
        {/* GENERIC SLIDE DECORATIONS */}
        <div className="theme-deco-slide-1"></div>
        <div className="theme-deco-slide-2"></div>

        <>
            {/* Text Section */}
            <div className={textContainerClasses} style={textOutroStyle}>
                <div className={`anim-content w-full ${textIntroClass}`} style={textIntroStyle}>
                    <span 
                        className={badgeClasses} 
                        style={{ fontSize: badgeFontSize ? `${badgeFontSize}px` : 'var(--slide-badge-size)' }}
                    >
                        {badge}
                    </span>

                    {/* Wrapped Title for Smooth Scaling */}
                    <div className="pulsate-wrapper mb-10 max-w-full" style={pulseWrapperStyle}>
                        <h1 className="slide-title font-bold leading-[1.1] whitespace-pre-wrap" style={titleStyle}>
                            {title}
                        </h1>
                    </div>

                    <p 
                        className={descClasses} 
                        style={{ fontSize: descriptionFontSize ? `${descriptionFontSize}px` : 'var(--slide-desc-size)' }}
                    >
                        {description}
                    </p>
                </div>
            </div>

            {/* Image Section - Only render if not text-only */}
            {!isTextOnly && (
                <div className={`flex-1 flex justify-center items-center relative z-10 h-full anim-outro-wrapper ${imgOutroClass}`} style={imgOutroStyle}>
                    <div className={`w-full h-full flex items-center justify-center anim-content ${imgIntroClass}`} style={imgIntroStyle}>
                        {/* Visual Wrapper for Effects */}
                        <div className="slide-visual-wrapper relative flex justify-center items-center">
                              <img 
                                  src={imageUrl} 
                                  alt="Slide Visual"
                                  crossOrigin="anonymous" 
                                  className="slide-image relative z-10 block"
                                  style={{ 
                                      maxHeight: 'var(--slide-img-max-height)', 
                                      maxWidth: '100%',
                                      objectFit: 'contain',
                                      margin: 0,
                                      padding: 0,
                                      border: 'none',
                                      outline: 'none',
                                      transform: 'none',
                                      boxShadow: 'inherit' // Allow themes to set box-shadow on image
                                  }}
                              />
                              {/* Dynamic Effect Layers - Controlled */}
                              <div className="slide-image-effect effect-1 absolute inset-0 z-0 pointer-events-none" style={getRippleStyle(0)}></div>
                              <div className="slide-image-effect effect-2 absolute inset-0 z-0 pointer-events-none" style={getRippleStyle(1)}></div>
                              <div className="slide-image-effect effect-3 absolute inset-0 z-0 pointer-events-none" style={getRippleStyle(2)}></div>
                        </div>
                    </div>
                </div>
            )}
        </>
      </div>
  );
};

export default SlideRenderer;

