.theme-terminal-matrix {
    background-color: #0c0c0c;
    color: #22c55e; /* Green-500 */
    text-align: left;
    position: relative;
    font-family: 'Courier New', monospace; /* Fallback if typography not set */

    /* Global Variable for Pulse Effect */
    --slide-accent-color: #22c55e;
}

/* Grid Overlay */
.theme-terminal-matrix::before {
    content: "";
    position: absolute;
    inset: 0;
    background-image: 
        linear-gradient(rgba(34, 197, 94, 0.1) 1px, transparent 1px),
        linear-gradient(90deg, rgba(34, 197, 94, 0.1) 1px, transparent 1px);
    background-size: 30px 30px;
    pointer-events: none;
    z-index: 0;
}

/* Prompt Badge */
.theme-terminal-matrix .badge {
    background: #000;
    color: #22c55e;
    border: 1px solid #22c55e;
    border-radius: 0;
    font-family: monospace;
    /* Digital Glow */
    box-shadow: 0 0 calc(10px * var(--badge-shadow-scale, 1)) rgba(34, 197, 94, 0.5);
}

.theme-terminal-matrix .badge::before {
    content: "> ";
}

.theme-terminal-matrix .slide-title {
    text-shadow: 0 0 10px rgba(34, 197, 94, 0.7);
}

.theme-terminal-matrix .slide-description {
    color: #86efac; /* Green-300 */
    background: rgba(0, 20, 0, 0.8);
    padding: 10px;
    border-left: 4px solid #22c55e;
}

/* Retro Monitor Image */
.theme-terminal-matrix .slide-image {
    box-sizing: content-box;
    border: 2px solid #22c55e;
    border-radius: 4px;
    /* Filter removed to show original colors */
    box-shadow: 0 0 20px rgba(34, 197, 94, 0.2);
}

.theme-terminal-matrix .slide-visual-wrapper {
    border-radius: 4px;
}

/* Deco 1: Scanline (simulated with gradient) */
.theme-terminal-matrix .theme-deco-slide-1 {
    position: absolute;
    inset: 0;
    background: linear-gradient(to bottom, rgba(255,255,255,0), rgba(255,255,255,0) 50%, rgba(0,0,0,0.1) 50%, rgba(0,0,0,0.1));
    background-size: 100% 4px;
    z-index: 100; /* On top of everything */
    pointer-events: none;
    opacity: 0.5;
}

/* Deco 2: Blinking Cursor Block (Static visual representation) */
.theme-terminal-matrix .theme-deco-slide-2 {
    position: absolute;
    bottom: 30px;
    right: 30px;
    width: 20px;
    height: 40px;
    background: #22c55e;
    animation: terminalBlink 1s infinite;
    z-index: 0;
}

@keyframes terminalBlink {
    0%, 100% { opacity: 1; }
    50% { opacity: 0; }
}
